import axios from 'axios'

const api = axios.create( {
    baseURL: process.env.REACT_APP_API_URL,
})

api.interceptors.request.use(config => {
    config.url = config.url + 'key=' + process.env.REACT_APP_API_KEY + '&q=Almaty&days=7';
    return config;
});

export default api;
